const root = $input.all()[0].json;
const out = [];
for (const name of root.names) {
  out.push({
    json: {
      name,
      dimensions: root.dimensions
    }
  });
}
return out;

const items = $input.all();
const out = [];
for (const item of items) {
  const name = item.json.name;
  const dimensions = item.json.dimensions;
  for (const key of Object.keys(dimensions)) {
    out.push({
      json: {
        name,
        dimension_key: key,
        dimension: dimensions[key]
      }
    });
  }
}
return out;

const name = $json.name;
const key = $json.dimension_key;
const dim = $json.dimension;

const allowedCodes = dim.categories.map(c => c.code);
const categoryLines = dim.categories.map(c => `- ${c.code}: ${c.description}`).join("\n");

const prompt = `You are a strict labeling agent.\n\nTarget organism: "${name}"\nDimension: "${key}"\nDimension description: ${dim.description}\n\nAllowed categories:\n${categoryLines}\n\nRules:\n- Select exactly one category code.\n- Must be one of: ${JSON.stringify(allowedCodes)}\n- Do not invent codes.\n- Output only JSON with exact shape:\n{"name":"${name}","dimension":"${key}","label":"<one_allowed_code>"}`;

return {
  json: {
    name,
    dimension: key,
    allowed: allowedCodes,
    prompt
  }
};

// Input node adın "Input" değilse değiştir
const dimensions = $items("Input")[0].json.dimensions;

// Gelen item'lar bazen tek item içinde array olabilir, bazen item-item gelebilir
const inItems = $input.all();
let records = [];

// 1) normalize: completion objelerini tek listeye topla
for (const it of inItems) {
  const j = it.json;
  if (Array.isArray(j)) {
    records.push(...j);
  } else if (Array.isArray(j.output)) {
    records.push(...j.output);
  } else if (j.choices) {
    records.push(j);
  } else if (Array.isArray(j.data)) {
    records.push(...j.data);
  }
}

if (records.length === 0) {
  throw new Error("No completion records found in Parse Validate input.");
}

// 2) parse + validate
const out = [];

for (const rec of records) {
  const raw = rec?.choices?.[0]?.message?.content;
  if (!raw) continue;

  let obj;
  try {
    obj = JSON.parse(String(raw).trim());
  } catch {
    const m = String(raw).match(/\{[\s\S]*\}/);
    if (!m) continue;
    obj = JSON.parse(m[0]);
  }

  const name = String(obj.name ?? "").trim();
  const dimension = String(obj.dimension ?? "").trim();
  const label = String(obj.label ?? "").trim();

  if (!name || !dimension || !label) continue;
  if (!dimensions[dimension]) continue;

  const allowed = dimensions[dimension].categories.map(c => c.code);
  if (!allowed.includes(label)) {
    throw new Error(`Invalid label '${label}' for ${name}/${dimension}`);
  }

  out.push({ json: { name, dimension, label } });
}

return out;

const items = $input.all();
const byName = new Map();

for (const item of items) {
  const { name, dimension, label } = item.json;
  if (!byName.has(name)) byName.set(name, { name });
  byName.get(name)[dimension] = label;
}

const rows = Array.from(byName.values()).sort((a, b) =>
  a.name.localeCompare(b.name, 'en', { sensitivity: 'base' })
);

return rows.map(row => ({ json: row }));
